mapper.sql:
SELECT DISTINCT ON (property.room_id) property.room_id, property.building_id, roster.unit_name, property.uid AS owner_uid, property.build_area, COALESCE(roster.building_name, CONCAT(property.building_id::TEXT, ' 号楼')) AS building_name, COALESCE(roster.room_name, property.room_id::TEXT) AS room_name FROM c_owner_property property LEFT JOIN LATERAL ( SELECT item.building_name, item.unit_name, item.room_name FROM c_property_roster item WHERE item.tenant_id = property.tenant_id AND item.room_id = property.room_id AND item.status = 'ACTIVE' ORDER BY item.roster_id LIMIT 1 ) roster ON TRUE WHERE property.tenant_id = #{tenantId} AND property.account_status = 1 AND property.verify_status = 'VERIFIED' AND property.build_area > 0
AND property.building_id = #{buildingId}
AND roster.unit_name = #{unitName}
ORDER BY property.room_id, property.is_voting_delegate DESC, property.uid

