    project_id, tenant_id, scope_type, building_id, unit_name,
    verification_status, verification_basis, legacy_read_only
) VALUES (
    #{projectId}, #{tenantId}, #{scopeType}, #{buildingId}, #{unitName},
    #{verificationStatus}, #{verificationBasis}, #{legacyReadOnly}
)

mapper.update:
UPDATE t_repair_project_decision_scope
SET verification_status = #{verificationStatus}, verification_basis = #{verificationBasis}
WHERE project_id = #{projectId}
  AND tenant_id = #{tenantId}
  AND legacy_read_only = FALSE

UPDATE t_repair_project_responsibility_determination
SET status = 'SUPERSEDED'
WHERE project_id = #{projectId}
  AND tenant_id = #{tenantId}
  AND status IN ('PENDING_CONFIRMATION', 'CONFIRMED')

UPDATE t_repair_project_responsibility_determination
SET status = 'CONFIRMED',
    confirmed_by_account_id = #{confirmedByAccountId},
    confirmed_by_user_id = #{confirmedByUserId},
    confirmed_at = CURRENT_TIMESTAMP,
    confirmation_note = #{confirmationNote}
WHERE determination_id = #{determinationId}
  AND project_id = #{projectId}
  AND tenant_id = #{tenantId}
  AND status = 'PENDING_CONFIRMATION'

