UPDATE t_repair_plan_version
SET status = 'AUTHORIZATION_FROZEN', authorization_snapshot_hash = #{authorizationSnapshotHash},
    authorization_frozen_by_user_id = #{frozenByUserId}, authorization_frozen_at = CURRENT_TIMESTAMP
WHERE plan_id = #{planId}
  AND project_id = #{projectId}
  AND tenant_id = #{tenantId}
  AND status = 'DRAFT'

UPDATE t_repair_project
SET active_plan_id = #{planId}, status = 'AUTHORIZATION_IN_PROGRESS',
    version = version + 1, update_time = CURRENT_TIMESTAMP
WHERE project_id = #{projectId}
  AND tenant_id = #{tenantId}
  AND version = #{expectedVersion}
  AND status = 'DRAFT'

UPDATE t_repair_project
SET active_plan_id = NULL, status = 'DRAFT',
    version = version + 1, update_time = CURRENT_TIMESTAMP
WHERE project_id = #{projectId}
  AND tenant_id = #{tenantId}
  AND status = #{expectedStatus}
  AND version = #{expectedVersion}

UPDATE t_repair_plan_version
SET status = 'LOCKED', snapshot_hash = #{snapshotHash},
    locked_by_user_id = #{lockedByUserId}, locked_at = CURRENT_TIMESTAMP
WHERE plan_id = #{planId}
  AND project_id = #{projectId}
  AND tenant_id = #{tenantId}
  AND status IN ('DRAFT', 'AUTHORIZATION_FROZEN')

UPDATE t_repair_plan_version
SET status = 'SUPERSEDED'
WHERE project_id = #{projectId}
  AND tenant_id = #{tenantId}
  AND plan_id <> #{exceptPlanId}
  AND status = 'LOCKED'

UPDATE t_repair_project
SET active_plan_id = #{planId}, status = #{nextStatus},
    version = version + 1, update_time = CURRENT_TIMESTAMP
WHERE project_id = #{projectId}
  AND tenant_id = #{tenantId}
  AND version = #{expectedVersion}
  AND status = #{expectedStatus}

UPDATE t_repair_project
SET version = version + 1, update_time = CURRENT_TIMESTAMP
WHERE project_id = #{projectId}
  AND tenant_id = #{tenantId}
  AND version = #{expectedVersion}

UPDATE t_repair_project
SET status = #{nextStatus}, version = version + 1, update_time = CURRENT_TIMESTAMP
WHERE project_id = #{projectId}
  AND tenant_id = #{tenantId}
  AND status = #{expectedStatus}
  AND version = #{expectedVersion}

